可以使用以下代码来调用SetWindowPos API，其中参数hWnd和hWndInsertAfter需要分别传入窗口句柄和HWND_NOTOPMOST：

```csharp
[DllImport("user32.dll", SetLastError = true)]
static extern bool SetWindowPos(IntPtr hWnd, IntPtr hWndInsertAfter, int x, int y, int cx, int cy, uint uFlags);

const uint SWP_NOMOVE = 0x0002;
const uint SWP_NOSIZE = 0x0001;
const uint SWP_NOZORDER = 0x0004;
const uint SWP_SHOWWINDOW = 0x0040;
static readonly IntPtr HWND_NOTOPMOST = new IntPtr(-2);  // 窗口插入序列号，表示不在顶部

// 调用示例
SetWindowPos(hWnd, HWND_NOTOPMOST, 0, 0, 0, 0, SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_SHOWWINDOW);
``` 

其中，SWP_NOMOVE、SWP_NOSIZE、SWP_NOZORDER和SWP_SHOWWINDOW是SetWindowPos API的参数，分别表示不移动窗口位置、不改变窗口大小、不改变窗口Z序列和显示窗口。

SystemParametersInfo API用于设置或检索系统范围的参数。其中有一种使用方式是使用SPI_SETWORKAREA常量来设置工作区域（桌面空间），该常量需要使用RECT结构体作为参数传递。在C#中，可以使用以下代码来调用SystemParametersInfo API并传递RECT参数：

```csharp
[DllImport("user32.dll", SetLastError = true)]
[return: MarshalAs(UnmanagedType.Bool)]
static extern bool SystemParametersInfo(uint uiAction, uint uiParam, ref RECT pvParam, uint fWinIni);

[StructLayout(LayoutKind.Sequential)]
public struct RECT
{
    public int Left, Top, Right, Bottom;
}

const uint SPI_SETWORKAREA = 0x002F;
const uint SPIF_SENDWININICHANGE = 0x02;

// 调用示例
RECT rect = new RECT
{
    Left = 100,
    Top = 100,
    Right = 800,
    Bottom = 600
};
bool result = SystemParametersInfo(SPI_SETWORKAREA, 0, ref rect, SPIF_SENDWININICHANGE);
```

在以上示例中，RECT结构体用于存储4个整数值，表示矩形的左、上、右、下边界坐标。在调用SystemParametersInfo API时，需要将RECT结构体传递给pvParam参数，使用ref关键字传递引用。注意，RECT结构体必须使用LayoutKind.Sequential特性进行标记，以确保其成员的顺序和内存布局与C++中的RECT结构体保持一致。调用SystemParametersInfo API时，还需要将参数fWinIni设置为常量SPIF_SENDWININICHANGE，以便将更改发送到所有打开的窗口。

在C#中，可以通过引入"User32.dll"来调用WndProc函数。需要注意的是，在C#中没有与C++中相同的函数签名。下面是一个示例实现：

```csharp
using System;
using System.Runtime.InteropServices;

class Program
{
    static void Main()
    {
        // 创建WNDCLASSEX结构体实例
        WNDCLASSEX winClss = new WNDCLASSEX
        {
            cbSize = Marshal.SizeOf(typeof(WNDCLASSEX)),
            style = CS_VREDRAW | CS_HREDRAW,
            lpfnWndProc = WndProc, // 使用C#的WndProc作为窗口过程函数
            hInstance = Marshal.GetHINSTANCE(typeof(Program).Module), // 获取当前模块句柄
            hCursor = LoadCursor(IntPtr.Zero, IDC_ARROW),
            hbrBackground = (IntPtr)(COLOR_BTNFACE + 1),
            lpszClassName = "MyWindowClass"
        };

        // 注册窗口类
        ushort atom = RegisterClassEx(ref winClss);
        if (atom == 0)
        {
            Console.WriteLine("RegisterClassEx failed.");
            return;
        }

        // 创建窗口
        IntPtr hwnd = CreateWindowEx(
            0,
            "MyWindowClass",
            "My Window",
            WS_OVERLAPPEDWINDOW,
            CW_USEDEFAULT,
            CW_USEDEFAULT,
            CW_USEDEFAULT,
            CW_USEDEFAULT,
            IntPtr.Zero,
            IntPtr.Zero,
            IntPtr.Zero,
            IntPtr.Zero);
        if (hwnd == IntPtr.Zero)
        {
            Console.WriteLine("CreateWindowEx failed.");
            return;
        }

        // 显示窗口
        ShowWindow(hwnd, SW_SHOW);
        UpdateWindow(hwnd);

        // 消息循环
        MSG msg = new MSG();
        while (GetMessage(out msg, IntPtr.Zero, 0, 0))
        {
            TranslateMessage(ref msg);
            DispatchMessage(ref msg);
        }
    }

    static IntPtr WndProc(IntPtr hwnd, uint uMsg, IntPtr wParam, IntPtr lParam)
    {
        switch (uMsg)
        {
            case WM_DESTROY:
                PostQuitMessage(0);
                break;
        }
        return DefWindowProc(hwnd, uMsg, wParam, lParam);
    }

    const uint CS_HREDRAW = 2;
    const uint CS_VREDRAW = 1;
    const int IDC_ARROW = 32512;
    const int COLOR_BTNFACE = 15;
    const uint WS_OVERLAPPEDWINDOW = 0x00CF0000;
    const int CW_USEDEFAULT = unchecked((int)0x80000000);
    const uint SW_SHOW = 5;

    [StructLayout(LayoutKind.Sequential)]
    struct MSG
    {
        public IntPtr hWnd;
        public uint message;
        public IntPtr wParam;
        public IntPtr lParam;
        public uint time;
        public int pt_x;
        public int pt_y;
    }

    [StructLayout(LayoutKind.Sequential)]
    struct WNDCLASSEX
    {
        public uint cbSize;
        public uint style;
        [MarshalAs(UnmanagedType.FunctionPtr)]
        public WindowProc lpfnWndProc; // 窗口过程函数指针
        public int cbClsExtra;
        public int cbWndExtra;
        public IntPtr hInstance;
        public IntPtr hIcon;
        public IntPtr hCursor;
        public IntPtr hbrBackground;
        public string lpszMenuName;
        public string lpszClassName;
        public IntPtr hIconSm;
    }

    delegate IntPtr WindowProc(IntPtr hWnd, uint uMsg, IntPtr wParam, IntPtr lParam); // 定义委托

    [DllImport("user32.dll")]
    static extern ushort RegisterClassEx(ref WNDCLASSEX lpWndClass);

    [DllImport("user32.dll")]
    static extern IntPtr CreateWindowEx(
        uint dwExStyle,
        string lpClassName,
        string lpWindowName,
        uint dwStyle,
        int x,
        int y,
        int nWidth,
        int nHeight,
        IntPtr hWndParent,
        IntPtr hMenu,
        IntPtr hInstance,
        IntPtr lpParam);

    [DllImport("user32.dll")]
    static extern bool ShowWindow(IntPtr hWnd, uint nCmdShow);

    [DllImport("user32.dll")]
    static extern bool UpdateWindow(IntPtr hWnd);

    [DllImport("user32.dll")]
    static extern bool GetMessage(out MSG lpMsg, IntPtr hWnd, uint wMsgFilterMin, uint wMsgFilterMax);

    [DllImport("user32.dll")]
    static extern bool TranslateMessage(ref MSG lpMsg);

    [DllImport("user32.dll")]
    static extern IntPtr DispatchMessage(ref MSG lpMsg);

    [DllImport("user32.dll")]
    static extern IntPtr LoadCursor(IntPtr hInstance, int lpCursorName);

    [DllImport("user32.dll", SetLastError = true)]
    static extern void PostQuitMessage(int nExitCode);

    [DllImport("user32.dll", SetLastError = true)]
    static extern IntPtr DefWindowProc(IntPtr hWnd, uint uMsg, IntPtr wParam, IntPtr lParam);
}
```

在上述示例中，使用WindowProc委托来定义WndProc函数指针，包含四个参数和返回值。使用Marshal.GetHINSTANCE方法获取当前程序的模块句柄。向系统注册窗口类和创建窗口都使用RegisterClassEx和CreateWindowEx函数。

在WndProc方法中，按照C++中WndProc的定义方式进行实现，根据不同消息类型来执行不同的操作。最后，如果窗口关闭，则调用PostQuitMessage方法终止消息循环。

GetCursorPos是Windows API中的一个函数，可以获取当前鼠标光标的位置。在C#中，需要使用DLLImport特性引入user32.dll库，并声明GetCursorPos函数。

以下是一个示例：

```csharp
using System;
using System.Runtime.InteropServices;

class Program
{
    static void Main()
    {
        POINT p;
        GetCursorPos(out p);

        Console.WriteLine("The cursor position is ({0}, {1})", p.X, p.Y);
    }

    [StructLayout(LayoutKind.Sequential)]
    struct POINT
    {
        public int X;
        public int Y;
    }

    [DllImport("user32.dll")]
    static extern bool GetCursorPos(out POINT lpPoint);
}
```

在以上示例中，使用GetCursorPos函数获取当前鼠标光标的位置，并且将结果输出。注意，在调用GetCursorPos函数时，需要传入一个POINT结构体的引用用于接收返回值。

同时，需要定义POINT结构体来存储获取的坐标。在C#中，结构体内的每个字段都需要显示声明其类型，并且需要使用LayoutKind.Sequential指定结构体的成员按照顺序排列。

最后，使用DllImport特性引用user32.dll库中的GetCursorPos函数。

InvalidateRect函数是Windows API中的一个函数，用于使指定的窗口客户区域无效，并请求重新绘制该区域。在C#中，需要使用DLLImport特性引入user32.dll库，并声明InvalidateRect函数。

以下是一个示例：

```csharp
using System;
using System.Runtime.InteropServices;

class Program
{
    static void Main()
    {
        IntPtr hwnd = IntPtr.Zero; // 这里输入你的窗口句柄
        RECT lpRect = new RECT(0, 0, 100, 100); // 这里输入你要重绘的矩形区域
        bool erase = true;  // 是否清除背景，true清除，false不清除

        InvalidateRect(hwnd, ref lpRect, erase);
    }

    [DllImport("user32.dll")]
    static extern int InvalidateRect(IntPtr hWnd, ref RECT lpRect, bool bErase);

    [StructLayout(LayoutKind.Sequential)]
    public struct RECT
    {
        public int left;
        public int top;
        public int right;
        public int bottom;

        public RECT(int left, int top, int right, int bottom)
        {
            this.left = left;
            this.top = top;
            this.right = right;
            this.bottom = bottom;
        }
    }
}
```

在以上示例中，输入你的窗口句柄与你要重绘的矩形区域，并通过调用InvalidateRect函数刷新区域。最后一个参数erase表示是否清除窗口背景，值为true会使窗口背景变黑，取值false则不清除。

同时，需要定义RECT结构体来存储绘制区域。在C#中，结构体内的每个字段都需要显示声明其类型，并通过构造函数对其进行初始化，并使用LayoutKind.Sequential指定结构体的成员按照顺序排列。

最后，使用DllImport特性引用user32.dll库中的InvalidateRect函数，从而在C#中实现调用该函数。

将 `InvalidateRect(hwnd, NULL, NULL)` 调用转换为 C# 代码后，应该如下所示：

```csharp
using System;
using System.Runtime.InteropServices;

class Program
{
    static void Main()
    {
        IntPtr hwnd = IntPtr.Zero; // 这里输入你的窗口句柄
        InvalidateRect(hwnd, IntPtr.Zero, false); // false表示不擦除背景
    }

    [DllImport("user32.dll")]
    static extern bool InvalidateRect(IntPtr hWnd, IntPtr lpRect, bool bErase);
}
```

在C#中，可以使用InvalidateRect方法来刷新指定窗口的无效客户区域。第一个参数hwnd表示窗口的句柄，第二个参数lpRect表示刷新的矩形区域，如果为IntPtr.Zero，则代表刷新整个窗口客户区域。第三个参数bErase表示是否擦除客户区域的背景，如果为false，则重绘时不擦除背景。

CreateCompatibleDC函数是Windows API中的一个函数，用于创建与指定的设备环境兼容的一个内存设备环境。在C#中，需要使用DLLImport特性引入gdi32.dll库，并声明CreateCompatibleDC函数。

以下是一个示例：

```csharp
using System;
using System.Runtime.InteropServices;

class Program
{
    static void Main()
    {
        IntPtr hdc = GetDC(IntPtr.Zero); // 获取屏幕的设备环境
        IntPtr hdcMem = CreateCompatibleDC(hdc); // 创建与屏幕设备环境兼容的内存设备环境
        ReleaseDC(IntPtr.Zero, hdc); // 释放屏幕的设备环境
        // 这里可以使用内存设备环境hdcMem进行操作
        // [...]

        DeleteDC(hdcMem); // 释放内存设备环境
    }

    [DllImport("gdi32.dll")]
    static extern IntPtr CreateCompatibleDC(IntPtr hdc);

    [DllImport("user32.dll")]
    static extern IntPtr GetDC(IntPtr hWnd);

    [DllImport("user32.dll")]
    static extern int ReleaseDC(IntPtr hWnd, IntPtr hDC);

    [DllImport("gdi32.dll")]
    static extern int DeleteDC(IntPtr hdc);
}
```

在以上示例中，首先获取屏幕的设备环境，然后使用CreateCompatibleDC函数创建一个与屏幕设备环境兼容的内存设备环境。可以在内存设备上进行绘图等操作。最后使用DeleteDC函数释放内存设备环境。GetDC与ReleaseDC函数用于获取和释放屏幕的设备环境，其中第一个参数为0代表获取和释放屏幕的设备环境。

注意，如果在使用CreateCompatibleDC函数创建的设备环境完成后不再使用，可以使用DeleteDC函数将其删除以释放资源，避免内存泄漏等问题。

CreateCompatibleBitmap、SelectObject、DeleteObject、GetClientRect、BitBlt等函数都属于GDI API，用于图形绘制和处理图像等操作。在C#中，需要使用DLLImport特性引入gdi32.dll库，并声明相关函数。

以下是一个示例：

```csharp
using System;
using System.Drawing;
using System.Drawing.Imaging;
using System.Runtime.InteropServices;

class Program
{
    static void Main()
    {
        IntPtr hdc = GetDC(IntPtr.Zero); // 获取屏幕的设备环境
        IntPtr hdcMem = CreateCompatibleDC(hdc); // 创建与屏幕设备环境兼容的内存设备环境

        RECT lpRect;
        GetClientRect(IntPtr.Zero, out lpRect); // 获取当前窗口大小
        IntPtr hBitmap = CreateCompatibleBitmap(hdc, lpRect.right - lpRect.left, lpRect.bottom - lpRect.top); // 创建兼容位图
        IntPtr hOld = SelectObject(hdcMem, hBitmap); // 选择位图

        // 使用内存设备环境hdcMem进行绘图等操作
        Graphics g = Graphics.FromHdc(hdcMem);
        g.FillRectangle(Brushes.Red, lpRect.left, lpRect.top, lpRect.right - lpRect.left, lpRect.bottom - lpRect.top);

        BitBlt(hdc, 0, 0, lpRect.right - lpRect.left, lpRect.bottom - lpRect.top, hdcMem, 0, 0, SRCCOPY); // 将内存设备环境中的位图拷贝至屏幕

        SelectObject(hdcMem, hOld); // 恢复原始位图
        DeleteObject(hBitmap); // 释放位图
        DeleteDC(hdcMem); // 释放内存设
